# RefCOCO (unc), single-dataset fine-tuning + HiLoRA, using the real MSCOCO-debiased
# CLIP checkpoint. Trimmed from train_single_dataset_finetuning_base.sh (unc block only)
# with placeholders substituted for our actual paths — reuses the same
# data_root/split_root our own pipeline already prepared (no separate copy needed):
#   data_root   = $SCRATCH/grounding_data            (data_root/other/images/mscoco/images/train2014)
#   split_root  = $SCRATCH/grounding_data/data        (split_root/unc/unc_{train,val,testA,testB}.pth)
#   clip_model  = the debiased clip_b_ml_cascade_maskrcnn_model_224.pth checkpoint
#   output_dir  = $SCRATCH/clip-kd-snn/HiVG_outputs/{output_v100..v103}/unc
#
# 8 GPUs (paper's stated setup; their actual released script used 7 — see our own
# HiVG-reimplementation discussion for why we standardized on 8 here too).

DATA_ROOT=$SCRATCH/grounding_data
SPLIT_ROOT=$SCRATCH/grounding_data/data
CLIP_CKPT=$SCRATCH/clip-kd-snn/clip_b_ml_cascade_maskrcnn_model_224.pth
OUT_ROOT=$SCRATCH/clip-kd-snn/HiVG_outputs

echo -e "\n\n\n\n\n\n\n==================== unc warmup ==========================="
# CUDA_VISIBLE_DEVICES=0,1,2,3,4,5,6,7 python -m torch.distributed.launch --nproc_per_node=8 --master_port 28887 --use_env hivg_train.py --num_workers 4 --epochs  60 --batch_size 80 --lr 0.00025  --lr_scheduler cosine --aug_crop --aug_scale --aug_translate   --vl_hidden_dim 512 --imsize 224 --max_query_len 77 --normalize_before --enable_adaptive_weights --dataset unc      --use_contrastive_loss  --use_rtcc_constrain_loss --use_mask_loss  --data_root $DATA_ROOT --split_root $SPLIT_ROOT --clip_model $CLIP_CKPT  --output_dir $OUT_ROOT/output_v100/unc --sup_type full;
CUDA_VISIBLE_DEVICES=0,1,2,3,4,5,6,7 python -m torch.distributed.launch --nproc_per_node=8 --master_port 28888 --use_env hivg_eval.py --num_workers 2 --batch_size 64  --dataset unc           --vl_hidden_dim 512 --imsize 224 --max_query_len 77 --normalize_before --enable_adaptive_weights --use_mask_loss --save_hilora_clip --data_root $DATA_ROOT --split_root $SPLIT_ROOT --eval_model $OUT_ROOT/output_v100/unc/best_checkpoint.pth --eval_set val      --output_dir $OUT_ROOT/output_v100/unc;
CUDA_VISIBLE_DEVICES=0,1,2,3,4,5,6,7 python -m torch.distributed.launch --nproc_per_node=8 --master_port 28888 --use_env hivg_eval.py --num_workers 2 --batch_size 64  --dataset unc           --vl_hidden_dim 512 --imsize 224 --max_query_len 77 --normalize_before --enable_adaptive_weights --use_mask_loss --save_hilora_clip --data_root $DATA_ROOT --split_root $SPLIT_ROOT --eval_model $OUT_ROOT/output_v100/unc/best_checkpoint.pth --eval_set testA    --output_dir $OUT_ROOT/output_v100/unc;
CUDA_VISIBLE_DEVICES=0,1,2,3,4,5,6,7 python -m torch.distributed.launch --nproc_per_node=8 --master_port 28888 --use_env hivg_eval.py --num_workers 2 --batch_size 64  --dataset unc           --vl_hidden_dim 512 --imsize 224 --max_query_len 77 --normalize_before --enable_adaptive_weights --use_mask_loss --save_hilora_clip --data_root $DATA_ROOT --split_root $SPLIT_ROOT --eval_model $OUT_ROOT/output_v100/unc/best_checkpoint.pth --eval_set testB    --output_dir $OUT_ROOT/output_v100/unc;
